var MAX_TERMINALS = 10;
var SCROLLBACK_MAX = 50 * 1024; // 50 KB per terminal

/**
 * Create a terminal manager for a project.
 * Manages persistent PTY sessions with scrollback buffering.
 * opts: { cwd, send, sendTo }
 */
function createTerminalManager(opts) {
  var cwd = opts.cwd;
  var send = opts.send;
  var sendTo = opts.sendTo;

  var nextId = 1;
  var terminals = new Map(); // id -> terminal session

  function create(cols, rows) {
    if (terminals.size > MAX_TERMINALS) return null;

    var pty = createTerminal(cwd, cols, rows);
    if (!pty) return null;

    var id = nextId++;
    var session = {
      id: id,
      pty: pty,
      scrollback: [],
      scrollbackSize: 0,
      cols: cols || 80,
      rows: rows || 24,
      title: "",
      closed: false
    };

    pty.on("data", function (data) {
      session.scrollback.push(data);
      session.scrollbackSize += data.length;

      while (session.scrollbackSize > SCROLLBACK_MAX) {
        var removed = session.scrollback.shift();
        session.scrollbackSize -= removed.length;
      }

      sendTo("terminal:data", { id: id, data: data });
    });

    pty.on("exit", function () {
      session.closed = true;
      sendTo("terminal:exit", { id: id });
    });

    terminals.set(id, session);
    sendTo("terminal:create", { id: id, cols: session.cols, rows: session.rows });
    return id;
  }

  function resize(id, cols, rows) {
    var session = terminals.get(id);
    if (!session) return;
    session.cols = cols;
    session.rows = rows;
    session.pty.resize(cols, rows);
  }

  function write(id, data) {
    var session = terminals.get(id);
    if (!session) return;
    session.pty.write(data);
  }

  function close(id) {
    var session = terminals.get(id);
    if (!session) return;
    session.pty.kill();
    terminals.delete(id);
  }

  return {
    create: create,
    resize: resize,
    write: write,
    close: close
  };
}

module.exports = { createTerminalManager };
